B.Pb=new A.h8("cow_gir","Gir","\u0917\u0940\u0930",B.cY,"Gir Hills, Gujarat","\u0917\u0940\u0930 \u092a\u0939\u093e\u095c\u093f\u092f\u093e\u0902, \u0917\u0941\u091c\u0930\u093e\u0924","Highly sought-after breed known for its distinctive curved horns and dome forehead. Producer of high quality nutritious milk.","\u0905\u092a\u0928\u0940 \u0918\u0941\u092e\u093e\u0935\u0926\u093e\u0930 \u0938\u0940\u0902\u0917\u094b\u0902 \u0914\u0930 \u0909\u092d\u0930\u0947 \u0939\u0941\u090f \u092e\u093e\u0925\u0947 \u0915\u0947 \u0932\u093f\u090f \u092a\u094d\u0930\u0938\u093f\u0926\u094d\u0927\u0964 \u0909\u091a\u094d\u091a \u0917\u0941\u0923\u0935\u0924\u094d\u0924\u093e \u0914\u0930 \u092a\u094b\u0937\u0915 \u0924\u0924\u094d\u0935\u094b\u0902 \u0938\u0947 \u092d\u0930\u092a\u0942\u0930 \u0926\u0942\u0927 \u0915\u093e \u0938\u094d\u0930\u094b\u0924\u0964","https://girorganic.com/cdn/shop/articles/what-is-gir-cow-453725.jpg?v=1673547600",B.rc,4.4,4.9,10,16,95,!0,"Suratgarh, Rajasthan","\u0938\u0942\u0930\u0924\u0917\u0922\u093c, \u0930\u093e\u091c\u0938\u094d\u0925\u093e\u0928",90)
