B.P8=new A.h8("cow_red_sindhi","Red Sindhi","\u0932\u093e\u0932 \u0938\u093f\u0902\u0927\u0940",B.cY,"Sindh region","\u0938\u093f\u0902\u0927 \u0915\u094d\u0937\u0947\u0924\u094d\u0930","Distinguished deep reddish-brown cow with high capability of resisting diseases and hot climate.","\u0917\u0939\u0930\u0947 \u0932\u093e\u0932-\u092d\u0942\u0930\u0947 \u0930\u0902\u0917 \u0915\u0940 \u092f\u0939 \u0917\u093e\u092f \u0930\u094b\u0917\u094b\u0902 \u0938\u0947 \u0932\u0921\u093c\u0928\u0947 \u0914\u0930 \u0917\u0930\u094d\u092e \u091c\u0932\u0935\u093e\u092f\u0941 \u092e\u0947\u0902 \u0930\u0939\u0928\u0947 \u0915\u0940 \u0905\u0926\u094d\u092d\u0941\u0924 \u0915\u094d\u0937\u092e\u0924\u093e \u0930\u0916\u0924\u0940 \u0939\u0948\u0964","https://akm-img-a-in.tosshub.com/lingo/ktak/images/story/202305/red_sindhi_cow-sixteen_nine.jpg?size=1200:675",B.dL,4.3,5,11,15,80,!0,"Kanpura, Jaipur","\u0915\u093e\u0928\u092a\u0941\u0930\u093e, \u091c\u092f\u092a\u0941\u0930",80)
B.Pf=new A.h8("cow_tharparkar","Tharparkar","\u0925\u093e\u0930\u092a\u093e\u0930\u0915\u0930",B.cY,"Thar Desert, Rajasthan","\u0925\u093e\u0930 \u092e\u0930\u0941\u0938\u094d\u0925\u0932, \u0930\u093e\u091c\u0938\u094d\u0925\u093e\u0928","Majestic white dual-purpose breed, extremely resilient to extreme desert environments.","\u0938\u092b\u0947\u0926 \u0930\u0902\u0917 \u0915\u0940 \u0936\u093e\u0928\u0926\u093e\u0930 \u0926\u094b\u0939\u0930\u0947 \u0909\u0926\u094d\u0926\u0947\u0936\u094d\u092f \u0935\u093e\u0932\u0940 \u0928\u0938\u094d\u0932, \u091c\u094b \u0930\u0947\u0917\u093f\u0938\u094d\u0924\u093e\u0928 \u0915\u0947 \u0905\u0924\u094d\u092f\u0902\u0924 \u0915\u0920\u093f\u0928 \u0935\u093e\u0924\u093e\u0935\u0930\u0923 \u092e\u0947\u0902 \u092d\u0940 \u0938\u0939\u091c \u0930\u0939\u0924\u0940 \u0939\u0948\u0964","https://breeds.okstate.edu/cattle/site-files/images/tharparkar.jpg",B.dL,4.2,4.8,9,14,75,!0,"Lunkaransar, Bikaner","\u0932\u0942\u0923\u0915\u0930\u0923\u0938\u0930, \u092c\u0940\u0915\u093e\u0928\u0947\u0930",110)
B.Pa=new A.h8("cow_rathi","Rathi","\u0930\u093e\u0920\u0940",B.cY,"Bikaner, Rajasthan","\u092c\u0940\u0915\u093e\u0928\u0947\u0930, \u0930\u093e\u091c\u0938\u094d\u0925\u093e\u0928","Docile, efficient milk producer requiring less feed maintenance, ideal for local village farms.","\u0936\u093e\u0902\u0924 \u0938\u094d\u0935\u092d\u093e\u0935 \u0914\u0930 \u0915\u092e \u091a\u093e\u0930\u0947 \u0915\u0947 \u0930\u0916-\u0930\u0916\u093e\u0935 \u092e\u0947\u0902 \u092d\u0940 \u0905\u091a\u094d\u091b\u093e \u0926\u0942\u0927 \u0926\u0947\u0928\u0947 \u0935\u093e\u0932\u0940 \u0938\u094d\u0925\u093e\u0928\u0940\u092f \u0921\u0947\u092f\u0930\u0940 \u0915\u093f\u0938\u093e\u0928\u094b\u0902 \u0915\u0947 \u0932\u093f\u090f \u0906\u0926\u0930\u094d\u0936 \u0917\u093e\u092f\u0964","https://cpimg.tistatic.com/05418407/b/4/Dairy-Rathi-Cow.jpg",B.dL,4,4.7,8.5,13,70,!0,"Khara, Rajasthan","\u0916\u093e\u0930\u093e, \u0930\u093e\u091c\u0938\u094d\u0925\u093e\u0928",140)
B.Pg=new A.h8("cow_kankrej","Kankrej","\u0915\u093e\u0902\u0915\u0930\u0947\u091c",B.cY,"Rann of Kutch, Gujarat","\u0915\u091a\u094d\u091b \u0915\u093e \u0930\u0923, \u0917\u0941\u091c\u0930\u093e\u0924","Known for its giant horns and unique heavy walk. Milk is rich in essential nutrients.",'\u0935\u093f\u0936\u093e\u0932 \u0938\u0940\u0902\u0917\u094b\u0902 \u0914\u0930 \u0905\u092a\u0928\u0940 \u0935\u093f\u0936\u0947\u0937 "\u0938\u0935\u093e\u0908 \u091a\u093e\u0932" \u0915\u0947 \u0932\u093f\u090f \u092a\u094d\u0930\u0938\u093f\u0926\u094d\u0927\u0964 \u0907\u0938\u0915\u093e \u0926\u0942\u0927 \u0906\u0935\u0936\u094d\u092f\u0915 \u092a\u094b\u0937\u0915 \u0924\u0924\u094d\u0935\u094b\u0902 \u0938\u0947 \u092d\u0930\u092a\u0942\u0930 \u0939\u094b\u0924\u093e \u0939\u0948\u0964',"https://cpimg.tistatic.com/03814100/b/5/Kankrej-Cows.jpg",B.dL,4.1,4.8,8,12,75,!1,"Jalore, Rajasthan","\u091c\u093e\u0932\u094c\u0930, \u0930\u093e\u091c\u0938\u094d\u0925\u093e\u0928",0)
