B.Pd=new A.h8("cow_jersey","Jersey","\u091c\u0930\u094d\u0938\u0940",B.cY,"Island of Jersey, UK","\u091c\u0930\u094d\u0938\u0940 \u0926\u094d\u0935\u0940\u092a, \u092f\u0942\u0915\u0947","Exotic breed producing high-butterfat milk. Highly responsive to customized farm feeds.","\u092e\u0915\u094d\u0916\u0928 \u0935\u0938\u093e \u0915\u0940 \u0909\u091a\u094d\u091a \u092e\u093e\u0924\u094d\u0930\u093e \u0935\u093e\u0932\u0947 \u0926\u0942\u0927 \u0915\u093e \u0909\u0924\u094d\u092a\u093e\u0926\u0928 \u0915\u0930\u0928\u0947 \u0935\u093e\u0932\u0940 \u0935\u093f\u0926\u0947\u0936\u0940 \u0928\u0938\u094d\u0932\u0964 \u0938\u0902\u0924\u0941\u0932\u093f\u0924 \u0906\u0939\u093e\u0930 \u0938\u0947 \u0926\u0942\u0927 \u0909\u0924\u094d\u092a\u093e\u0926\u0928 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b\u0924\u093e \u0939\u0948\u0964","https://cpimg.tistatic.com/07978449/b/4/Cross-Breed-HF-Cow.jpg",B.rd,4.8,5.5,14,22,65,!0,"Bilwa, Rajasthan","\u092c\u093f\u0932\u094d\u0935\u093e, \u0930\u093e\u091c\u0938\u094d\u0925\u093e\u0928",150)
B.Pc=new A.h8("cow_hf","Holstein Friesian (HF)","\u0939\u094b\u0932\u094d\u0938\u094d\u091f\u0940\u0928 \u092b\u094d\u0930\u093f\u0938\u093f\u092f\u0928",B.cY,"Netherlands","\u0928\u0940\u0926\u0930\u0932\u0948\u0902\u0921","Highest milk yield volume producer globally. Striking black and white patched coat.","\u0926\u0941\u0928\u093f\u092f\u093e \u092e\u0947\u0902 \u0938\u092c\u0938\u0947 \u0905\u0927\u093f\u0915 \u092e\u093e\u0924\u094d\u0930\u093e \u092e\u0947\u0902 \u0926\u0942\u0927 \u0926\u0947\u0928\u0947 \u0935\u093e\u0932\u0940 \u0928\u0938\u094d\u0932\u0964 \u0915\u093e\u0932\u0947 \u0914\u0930 \u0938\u092b\u0947\u0926 \u0927\u092c\u094d\u092c\u094b\u0902 \u0935\u093e\u0932\u093e \u0906\u0915\u0930\u094d\u0937\u0915 \u0936\u0930\u0940\u0930\u0964","https://www.dairymitra.com/uploads/product/16714427017786.jpg",B.rd,3.5,4,20,30,60,!0,"Watika, Rajasthan","\u0935\u093e\u091f\u093f\u0915\u093e, \u0930\u093e\u091c\u0938\u094d\u0925\u093e\u0928",250)
B.P5=new A.h8("buffalo_murrah","Murrah","\u092e\u0941\u0930\u094d\u0930\u093e",B.hG,"Haryana / Punjab","\u0939\u0930\u093f\u092f\u093e\u0923\u093e / \u092a\u0902\u091c\u093e\u092c",'Known as the "Black Gold" of dairy farming. Famous for curly horns and rich fat yields.','\u0921\u0947\u092f\u0930\u0940 \u092b\u093e\u0930\u094d\u092e\u093f\u0902\u0917 \u0915\u093e "\u0915\u093e\u0932\u093e \u0938\u094b\u0928\u093e"\u0964 \u0918\u0941\u092e\u093e\u0935\u0926\u093e\u0930 \u0938\u0940\u0902\u0917\u094b\u0902 \u0914\u0930 \u092e\u0932\u093e\u0908\u0926\u093e\u0930 \u0909\u091a\u094d\u091a \u0935\u0938\u093e \u0935\u093e\u0932\u0947 \u0926\u0942\u0927 \u0915\u0947 \u0932\u093f\u090f \u0935\u093f\u0936\u094d\u0935 \u092a\u094d\u0930\u0938\u093f\u0926\u094d\u0927\u0964',"https://cpimg.tistatic.com/05880257/b/4/Pure-Murrah-Buffalo.jpg",B.dL,6.8,7.8,14,20,90,!0,"Rohtak, Haryana","\u0930\u094b\u0939\u0924\u0915, \u0939\u0930\u093f\u092f\u093e\u0923\u093e",180)
