B.P6=new A.h8("buffalo_mehsana","Mehsana","\u092e\u0947\u0939\u0938\u093e\u0928\u093e",B.hG,"Mehsana, Gujarat","\u092e\u0947\u0939\u0938\u093e\u0928\u093e, \u0917\u0941\u091c\u0930\u093e\u0924","A reliable crossbreed of Murrah and Surti known for extended lactation and gentle temperament.","\u092e\u0941\u0930\u094d\u0930\u093e \u0914\u0930 \u0938\u0941\u0930\u0924\u0940 \u0915\u093e \u0935\u093f\u0936\u094d\u0935\u0938\u0928\u0940\u092f \u0938\u0902\u0915\u0930\u0923, \u091c\u094b \u0932\u0902\u092c\u0947 \u0938\u092e\u092f \u0924\u0915 \u0928\u093f\u092f\u092e\u093f\u0924 \u0926\u0942\u0927 \u0926\u0947\u0928\u0947 \u0914\u0930 \u0936\u093e\u0902\u0924 \u0938\u094d\u0935\u092d\u093e\u0935 \u0915\u0947 \u0932\u093f\u090f \u091c\u093e\u0928\u093e \u091c\u093e\u0924\u093e \u0939\u0948\u0964","https://tiimg.tistatic.com/fp/1/005/259/mehsana-buffalo-353.jpg",B.dL,6.5,7.5,10,15,80,!0,"Palanpur, Gujarat","\u092a\u093e\u0932\u0928\u092a\u0941\u0930, \u0917\u0941\u091c\u0930\u093e\u0924",110)
